"use client"

import { cn } from "@/lib/utils"
import { BitcoinAvatarUI } from "./ui"
import {
  useBitcoinAvatar,
  type UseBitcoinAvatarReturn,
  type UseBitcoinAvatarOptions,
} from "./use-bitcoin-avatar"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { BitcoinAvatarUI, type BitcoinAvatarUIProps } from "./ui"
export {
  useBitcoinAvatar,
  type UseBitcoinAvatarReturn,
  type UseBitcoinAvatarOptions,
} from "./use-bitcoin-avatar"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Supported avatar variant styles from sigma-avatars */
type AvatarVariant =
  | "marble"
  | "pixel"
  | "beam"
  | "ring"
  | "sunset"
  | "bauhaus"
  | "fractal"
  | "mage"
  | "barcode"
  | "pepe"

export interface BitcoinAvatarProps {
  /** Bitcoin address or BAP ID used as the deterministic seed */
  address: string
  /** On-chain image URL (ord://, b://, bitfs://) to resolve and display */
  imageUrl?: string
  /** Size variant: sm=32, md=40, lg=64, xl=96 */
  size?: "sm" | "md" | "lg" | "xl"
  /** Visual style for the deterministic fallback avatar */
  variant?: AvatarVariant
  /** Optional CSS class name */
  className?: string
}

const SIZE_MAP: Record<"sm" | "md" | "lg" | "xl", number> = {
  sm: 32,
  md: 40,
  lg: 64,
  xl: 96,
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * A hybrid avatar component for Bitcoin addresses.
 *
 * When `imageUrl` is provided (e.g. `ord://txid`), it resolves the on-chain
 * image via `bitcoin-image` and displays it. If resolution fails or no
 * `imageUrl` is given, it renders a deterministic SVG avatar from
 * `sigma-avatars` seeded by the `address` prop.
 */
export function BitcoinAvatar({
  address,
  imageUrl,
  size = "md",
  variant = "marble",
  className,
}: BitcoinAvatarProps) {
  const px = SIZE_MAP[size]
  const hook = useBitcoinAvatar({ address, imageUrl })

  return (
    <BitcoinAvatarUI
      address={address}
      px={px}
      variant={variant}
      className={className}
      showOnChainImage={hook.showOnChainImage}
      resolvedUrl={hook.resolvedUrl}
      onImageError={hook.markResolutionFailed}
    />
  )
}

"use client"

import Avatar, { defaultColors } from "sigma-avatars"
import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Supported avatar variant styles from sigma-avatars */
type AvatarVariant =
  | "marble"
  | "pixel"
  | "beam"
  | "ring"
  | "sunset"
  | "bauhaus"
  | "fractal"
  | "mage"
  | "barcode"
  | "pepe"

export interface BitcoinAvatarUIProps {
  /** Bitcoin address or BAP ID used as the deterministic seed */
  address: string
  /** Size in pixels */
  px: number
  /** Visual style for the deterministic fallback avatar */
  variant?: AvatarVariant
  /** Optional CSS class name */
  className?: string
  /** Whether to show the resolved on-chain image */
  showOnChainImage: boolean
  /** The resolved HTTP URL for the on-chain image */
  resolvedUrl: string | null
  /** Callback when the on-chain <img> fails to load */
  onImageError: () => void
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function BitcoinAvatarUI({
  address,
  px,
  variant = "marble",
  className,
  showOnChainImage,
  resolvedUrl,
  onImageError,
}: BitcoinAvatarUIProps) {
  if (showOnChainImage && resolvedUrl) {
    return (
      <img
        src={resolvedUrl}
        alt={`Avatar for ${address.slice(0, 8)}...`}
        width={px}
        height={px}
        className={cn("rounded-full object-cover", className)}
        data-testid="bitcoin-avatar"
        onError={onImageError}
      />
    )
  }

  // Deterministic fallback via sigma-avatars
  return (
    <div
      className={cn("inline-flex shrink-0", className)}
      data-testid="bitcoin-avatar"
    >
      <Avatar
        name={address}
        variant={variant}
        size={px}
        colors={defaultColors}
        className="rounded-full"
      />
    </div>
  )
}

import { useCallback, useEffect, useState } from "react"
import { ImageProtocols } from "bitcoin-image"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface UseBitcoinAvatarOptions {
  /** Bitcoin address or BAP ID used as the deterministic seed */
  address: string
  /** On-chain image URL (ord://, b://, bitfs://) to resolve and display */
  imageUrl?: string
}

export interface UseBitcoinAvatarReturn {
  /** The resolved HTTP URL for the on-chain image, or null */
  resolvedUrl: string | null
  /** Whether the on-chain image resolution failed */
  resolutionFailed: boolean
  /** Whether to show the on-chain image vs the deterministic avatar */
  showOnChainImage: boolean
  /** Mark the on-chain image as failed (e.g. on <img> load error) */
  markResolutionFailed: () => void
}

// ---------------------------------------------------------------------------
// Singleton ImageProtocols instance shared across all BitcoinAvatar mounts
// ---------------------------------------------------------------------------

let sharedImageProtocols: ImageProtocols | null = null

function getImageProtocols(): ImageProtocols {
  if (!sharedImageProtocols) {
    sharedImageProtocols = new ImageProtocols({
      cacheEnabled: true,
      cacheTTL: 3600,
    })
  }
  return sharedImageProtocols
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useBitcoinAvatar({
  address,
  imageUrl,
}: UseBitcoinAvatarOptions): UseBitcoinAvatarReturn {
  const [resolvedUrl, setResolvedUrl] = useState<string | null>(null)
  const [resolutionFailed, setResolutionFailed] = useState(false)

  // Resolve on-chain image URL when provided
  useEffect(() => {
    if (!imageUrl) {
      setResolvedUrl(null)
      setResolutionFailed(false)
      return
    }

    let cancelled = false
    setResolutionFailed(false)

    const protocols = getImageProtocols()
    protocols
      .getDisplayUrl(imageUrl)
      .then((url) => {
        if (cancelled) return
        // ImageProtocols returns its fallback data URI on failure;
        // treat that as a failed resolution so we show the sigma avatar
        const parsed = protocols.parse(imageUrl)
        if (!parsed.isValid) {
          setResolutionFailed(true)
          return
        }
        setResolvedUrl(url)
      })
      .catch(() => {
        if (!cancelled) {
          setResolutionFailed(true)
        }
      })

    return () => {
      cancelled = true
    }
  }, [imageUrl])

  const showOnChainImage = Boolean(imageUrl && resolvedUrl && !resolutionFailed)

  const markResolutionFailed = useCallback(() => {
    setResolutionFailed(true)
  }, [])

  return {
    resolvedUrl,
    resolutionFailed,
    showOnChainImage,
    markResolutionFailed,
  }
}
